		Failed:          m.Failed,
		PushFailed:      m.PushFailed,
		TotalDurationMS: m.TotalDurationMS,
		TotalCommits:    m.TotalCommits,
	}
}

// workerDispatchAdapter implements GraphQL action dispatch using the live
// WorkerManager.
type workerDispatchAdapter struct {
	manager *WorkerManager
}

func (a *workerDispatchAdapter) DispatchWorker(ctx context.Context, kind string, projectRoot string, rawArgs *string) (*ddxgraphql.WorkerDispatchResult, error) {
	if a == nil || a.manager == nil {
		return nil, fmt.Errorf("worker dispatcher is not configured")
	}
	if err := ctx.Err(); err != nil {
		return nil, err
	}
	if kind != "execute-loop" {
		return nil, fmt.Errorf("unsupported worker kind %q", kind)
	}

	var req struct {
		Harness       string `json:"harness"`
		Model         string `json:"model"`
		Profile       string `json:"profile"`
		Provider      string `json:"provider"`
		ModelRef      string `json:"model_ref"`
		Effort        string `json:"effort"`
		LabelFilter   string `json:"label_filter"`
		Once          bool   `json:"once"`
		PollInterval  string `json:"poll_interval"`
		NoReview      bool   `json:"no_review"`
		ReviewHarness string `json:"review_harness"`
		ReviewModel   string `json:"review_model"`
	}
	if rawArgs != nil && *rawArgs != "" {
		if err := json.Unmarshal([]byte(*rawArgs), &req); err != nil {
			return nil, fmt.Errorf("invalid worker args JSON: %w", err)
		}
	}

	// Apply .ddx/config.yaml workers.default_spec + enforce workers.max_count
	// (ddx-b6cf025c). The max_count cap counts currently-running drain workers
	// for this project so the "+ Add worker" button can refuse cleanly.
	if wc := loadWorkersConfig(projectRoot); wc != nil {
		if spec := wc.DefaultSpec; spec != nil {
			if req.Harness == "" {
				req.Harness = spec.Harness
			}
			if req.Profile == "" {
				req.Profile = spec.Profile
			}
			if req.Effort == "" {
				req.Effort = spec.Effort
			}
		}
		if wc.MaxCount != nil && *wc.MaxCount >= 0 {
			running := a.countRunningDrainWorkers(projectRoot)
			if running >= *wc.MaxCount {
				return nil, fmt.Errorf("workers.max_count cap reached: %d running (limit %d)", running, *wc.MaxCount)
			}
		}
	}

	// Default-path contract (ddx-755f5881 AC #1): an empty dispatch input
	// (no rawArgs, no workers.default_spec) must produce a spec with
	// Profile: "default" and nothing else. This eliminates the historical
	// 19-burn drain-queue failure mode where an empty spec fanned out into
	// per-tier ladder iteration with no upstream synthesis target.
	if req.Profile == "" {
		req.Profile = "default"
	}

	// Default poll-interval = 30s for server-managed workers (ddx-dc157075).
	// Operators wanting drain-and-exit semantics must pass --once or an
	// explicit poll_interval=0 in the dispatch payload.
	pollInterval := 30 * time.Second
	if req.PollInterval != "" {
		d, err := time.ParseDuration(req.PollInterval)
		if err != nil {
			return nil, fmt.Errorf("invalid poll_interval: %w", err)
		}
		pollInterval = d
	}

	record, err := a.manager.StartExecuteLoop(ExecuteLoopWorkerSpec{
		ProjectRoot:   projectRoot,
		Harness:       req.Harness,
		Model:         req.Model,
		Profile:       req.Profile,
		Provider:      req.Provider,
		ModelRef:      req.ModelRef,
		Effort:        req.Effort,
		LabelFilter:   req.LabelFilter,
		Once:          req.Once,
		PollInterval:  pollInterval,
		NoReview:      req.NoReview,
		ReviewHarness: req.ReviewHarness,
		ReviewModel:   req.ReviewModel,
	})
	if err != nil {
		return nil, err
	}
	return &ddxgraphql.WorkerDispatchResult{
		ID:    record.ID,
		State: record.State,
		Kind:  record.Kind,
	}, nil
}

// loadWorkersConfig reads .ddx/config.yaml at projectRoot and returns the
// workers block, or nil when unset / on error. Errors are swallowed because
// a missing or malformed config must not block the dispatch path.
func loadWorkersConfig(projectRoot string) *config.WorkersConfig {
	if projectRoot == "" {
		return nil
	}
	cfg, err := config.LoadWithWorkingDir(projectRoot)
	if err != nil || cfg == nil {
		return nil
	}
	return cfg.Workers
}

// countRunningDrainWorkers counts execute-loop workers currently in state
// "running" for projectRoot. Returns 0 on any error.
func (a *workerDispatchAdapter) countRunningDrainWorkers(projectRoot string) int {
	if a == nil || a.manager == nil {
		return 0
	}
	recs, err := a.manager.List()
	if err != nil {
		return 0
	}
	count := 0
	for _, rec := range recs {
		if rec.Kind == "execute-loop" && rec.State == "running" && rec.ProjectRoot == projectRoot {
			count++
		}
	}
	return count
}

func (a *workerDispatchAdapter) DispatchPlugin(ctx context.Context, projectRoot string, name string, action string, scope string) (*ddxgraphql.PluginDispatchResult, error) {
	if a == nil || a.manager == nil {
		return nil, fmt.Errorf("worker dispatcher is not configured")
	}
	if err := ctx.Err(); err != nil {
		return nil, err
	}
	record, err := a.manager.StartPluginAction(PluginActionWorkerSpec{
		ProjectRoot: projectRoot,
		Name:        name,
		Action:      action,
		Scope:       scope,
	}, func(runCtx context.Context) (string, error) {
		if err := runCtx.Err(); err != nil {
			return "", err
		}
		return ddxgraphql.DispatchPluginAction(projectRoot, name, action)
	})
	if err != nil {
		return nil, err
	}
	return &ddxgraphql.PluginDispatchResult{
		ID:     record.ID,
		State:  record.State,
		Action: action,
	}, nil
}

func (a *workerDispatchAdapter) StopWorker(ctx context.Context, id string) (*ddxgraphql.WorkerLifecycleResult, error) {
	if a == nil || a.manager == nil {
		return nil, fmt.Errorf("worker dispatcher is not configured")
	}
	if err := ctx.Err(); err != nil {
		return nil, err
	}
	if err := a.manager.Stop(id); err != nil {
		return nil, err
	}
	rec, err := a.manager.Show(id)
	if err != nil {
		return &ddxgraphql.WorkerLifecycleResult{ID: id, State: "stopping", Kind: "execute-loop"}, nil
	}
	return &ddxgraphql.WorkerLifecycleResult{
		ID:    rec.ID,
		State: rec.State,
		Kind:  rec.Kind,
	}, nil
}

package metric

import (
	"context"
	"fmt"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
	ddxexec "github.com/DocumentDrivenDX/ddx/internal/exec"
)

var errNotMetricArtifact = fmt.Errorf("not a metric artifact")

type Store struct {
	WorkingDir string
	execStore  *ddxexec.Store
}

func NewStore(workingDir string) *Store {
	return &Store{
		WorkingDir: workingDir,
		execStore:  ddxexec.NewStore(workingDir),
	}
}

// ListArtifacts returns all MET-* artifacts in document ID order.
func (s *Store) ListArtifacts() ([]docgraph.Document, error) {
	graph, err := docgraph.BuildGraph(s.WorkingDir)
	if err != nil {
		return nil, err
	}
	ids := graph.All()
	out := make([]docgraph.Document, 0, len(ids))
	for _, id := range ids {
		if !strings.HasPrefix(id, "MET-") {
			continue
		}
		doc, ok := graph.Show(id)
		if !ok {
			continue
		}
		out = append(out, doc)
	}
	return out, nil
}

func (s *Store) Validate(metricID string) (*Definition, *docgraph.Document, error) {
	doc, err := s.loadMetricArtifact(metricID)
	if err != nil {
		return nil, nil, err
	}
	def, err := s.LoadDefinition(metricID)
	if err != nil {
		return nil, nil, err
	}
	if def.MetricID != metricID {
		return nil, nil, fmt.Errorf("metric definition %q does not target %q", def.DefinitionID, metricID)
	}
	if len(def.Command) == 0 {
		return nil, nil, fmt.Errorf("metric definition %q has no command", def.DefinitionID)
	}
	if def.Comparison == "" {
		def.Comparison = ComparisonLowerIsBetter
	}
	switch def.Comparison {
	case ComparisonLowerIsBetter, ComparisonHigherIsBetter:
	default:
		return nil, nil, fmt.Errorf("metric definition %q has invalid comparison %q", def.DefinitionID, def.Comparison)
	}
	return &def, doc, nil
}

func (s *Store) Run(ctx context.Context, metricID string) (HistoryRecord, error) {
	def, _, err := s.Validate(metricID)
	if err != nil {
		return HistoryRecord{}, err
	}
	rec, err := s.execStore.Run(ctx, def.DefinitionID)
	if err != nil {
		return HistoryRecord{}, err
	}
	return metricHistoryFromExec(rec)
}

func (s *Store) Compare(metricID, against string) (HistoryRecord, ComparisonResult, error) {
	history, err := s.History(metricID)
	if err != nil {
		return HistoryRecord{}, ComparisonResult{}, err
	}
	if len(history) == 0 {
		return HistoryRecord{}, ComparisonResult{}, fmt.Errorf("no history for metric %q", metricID)
	}
	if _, err := singleHistoryUnit(metricID, history); err != nil {
		return HistoryRecord{}, ComparisonResult{}, err
	}
	current := history[len(history)-1]
	target, err := selectComparisonTarget(history, against)
	if err != nil {
		return HistoryRecord{}, ComparisonResult{}, err
	}
	result := comparisonFor(current.Value, target.Value, current.Comparison.Direction)
	current.Comparison = result
	return current, result, nil
}

func (s *Store) Trend(metricID string) (TrendSummary, error) {
	history, err := s.History(metricID)
	if err != nil {
		return TrendSummary{}, err
	}
	if len(history) == 0 {
		return TrendSummary{}, fmt.Errorf("no history for metric %q", metricID)
	}
	unit, err := singleHistoryUnit(metricID, history)
	if err != nil {
		return TrendSummary{}, err
	}
	summary := TrendSummary{MetricID: metricID, Min: history[0].Value, Max: history[0].Value, Latest: history[len(history)-1].Value, Unit: unit, UpdatedAt: history[len(history)-1].ObservedAt}
	var sum float64
	for _, rec := range history {
		if rec.Value < summary.Min {
			summary.Min = rec.Value
		}
		if rec.Value > summary.Max {
			summary.Max = rec.Value
		}
		sum += rec.Value
		summary.UpdatedAt = rec.ObservedAt
	}
	summary.Count = len(history)
	summary.Average = sum / float64(len(history))
	return summary, nil
}

// GroupedHistory returns history rows partitioned by unit while preserving
// the observed order within each unit group.
func (s *Store) GroupedHistory(metricID string) ([]HistoryGroup, error) {
	history, err := s.History(metricID)
	if err != nil {
		return nil, err
	}
	return groupHistoryByUnit(history), nil
}

func (s *Store) LoadDefinition(metricID string) (Definition, error) {
	if s.execStore == nil {
		return Definition{}, fmt.Errorf("metric store is not initialized")
	}
	defs, err := s.execStore.ListDefinitions(metricID)
	if err != nil {
		return Definition{}, err
	}
	var (
		best  Definition
		found bool
	)
	for _, def := range defs {
		if def.ID == "" {
			continue
		}
		mapped, err := metricDefinitionFromExec(def)
		if err != nil {
			return Definition{}, err
		}
		if mapped.MetricID != metricID || !mapped.Active {
			continue
		}
		if !found || mapped.CreatedAt.After(best.CreatedAt) || (mapped.CreatedAt.Equal(best.CreatedAt) && mapped.DefinitionID > best.DefinitionID) {
			best = mapped
			found = true
		}
	}
	if !found {
		return Definition{}, fmt.Errorf("metric definition for %q not found", metricID)
	}
	if best.DefinitionID == "" {
		return Definition{}, fmt.Errorf("metric definition for %q is missing definition_id", metricID)
	}
	return best, nil
}

func (s *Store) History(metricID string) ([]HistoryRecord, error) {
	if s.execStore == nil {
		return []HistoryRecord{}, fmt.Errorf("metric store is not initialized")
	}
	records, err := s.execStore.History(metricID, "")
	if err != nil {
		return nil, err
	}
	out := make([]HistoryRecord, 0, len(records))
	for _, rec := range records {
		mapped, err := metricHistoryFromExec(rec)
		if err != nil {
			return nil, err
		}
		if mapped.MetricID == metricID {
			out = append(out, mapped)
		}
	}
	return out, nil
}

func (s *Store) loadMetricArtifact(metricID string) (*docgraph.Document, error) {
	if !strings.HasPrefix(metricID, "MET-") {
		return nil, fmt.Errorf("%w: %s", errNotMetricArtifact, metricID)
	}
	graph, err := docgraph.BuildGraph(s.WorkingDir)
	if err != nil {
		return nil, err
	}
	doc, ok := graph.Show(metricID)
	if !ok {
		return nil, fmt.Errorf("metric artifact %q not found", metricID)
	}
	return &doc, nil
}

